'use client';

import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { MapPin } from 'lucide-react';

export default function Hero() {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    phone: '',
    program: '',
    destination: '',
  });

  const [submitted, setSubmitted] = useState(false);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData((prev) => ({ ...prev, [name]: value }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch('/api/submit-lead', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData),
      });

      if (!response.ok) {
        const data = await response.json();
        throw new Error(data.error || 'Submission failed. Please try again.');
      }

      setSubmitted(true);
      setTimeout(() => {
        setSubmitted(false);
        setFormData({ name: '', email: '', phone: '', program: '', destination: '' });
      }, 3000);
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Something went wrong. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <section className="bg-gradient-to-b from-primary to-primary/95 text-white py-20 sm:py-32">
      <div className="container mx-auto px-4 sm:px-6">
        <div className="grid lg:grid-cols-2 gap-16 items-start">
          {/* Left Content */}
          <div className="space-y-8">
            <div className="space-y-6">
              <h1 className="text-5xl sm:text-6xl lg:text-7xl font-bold leading-tight">
                Get Admitted to Your Dream University Abroad
              </h1>
              <p className="text-lg text-white/90 leading-relaxed max-w-md">
                Experience a seamless journey to global excellence with expert guidance for MBBS, Engineering, MBA &amp; PhD programs in the world&apos;s top destinations.
              </p>
            </div>

            {/* Quick Stats */}
            <div className="grid grid-cols-3 gap-8 pt-4">
              <div>
                <p className="text-4xl font-bold text-accent">500+</p>
                <p className="text-sm text-white/80 mt-2">Students Placed</p>
              </div>
              <div>
                <p className="text-4xl font-bold text-accent">10+</p>
                <p className="text-sm text-white/80 mt-2">Years Experience</p>
              </div>
              <div>
                <p className="text-4xl font-bold text-accent">98%</p>
                <p className="text-sm text-white/80 mt-2">Success Rate</p>
              </div>
            </div>
          </div>

          {/* Right Content - Form */}
          <div className="bg-white rounded-2xl p-8 sm:p-10 shadow-xl">
            {/* Badge */}
            <div className="flex justify-center mb-4">
              <span className="inline-flex items-center gap-1.5 bg-accent/10 text-accent text-xs font-bold tracking-widest uppercase px-4 py-2 rounded-full border border-accent/20">
                <MapPin className="w-3.5 h-3.5" />
                Over 5,000+ Students Successfully Placed
              </span>
            </div>

            <h2 className="text-2xl sm:text-3xl font-bold text-foreground mb-8">Get Your Free Consultation</h2>

            {submitted ? (
              <div className="space-y-4 text-center py-16">
                <div className="text-5xl mb-4">✓</div>
                <h3 className="text-2xl font-bold text-foreground">Thank You!</h3>
                <p className="text-foreground/70">Your inquiry has been received. Our team will contact you within 24 hours.</p>
              </div>
            ) : (
              <form onSubmit={handleSubmit} className="space-y-5">
                <div>
                  <label htmlFor="name" className="block text-sm font-semibold text-foreground mb-2">
                    Full Name
                  </label>
                  <input
                    type="text"
                    id="name"
                    name="name"
                    value={formData.name}
                    onChange={handleChange}
                    required
                    placeholder="Your full name"
                    className="w-full px-4 py-3 bg-background border border-border rounded-md text-foreground placeholder:text-foreground/40 focus:outline-none focus:ring-2 focus:ring-accent/50 transition"
                  />
                </div>

                <div>
                  <label htmlFor="email" className="block text-sm font-semibold text-foreground mb-2">
                    Email
                  </label>
                  <input
                    type="email"
                    id="email"
                    name="email"
                    value={formData.email}
                    onChange={handleChange}
                    required
                    placeholder="your@email.com"
                    className="w-full px-4 py-3 bg-background border border-border rounded-md text-foreground placeholder:text-foreground/40 focus:outline-none focus:ring-2 focus:ring-accent/50 transition"
                  />
                </div>

                <div>
                  <label htmlFor="phone" className="block text-sm font-semibold text-foreground mb-2">
                    Phone
                  </label>
                  <input
                    type="tel"
                    id="phone"
                    name="phone"
                    value={formData.phone}
                    onChange={handleChange}
                    required
                    placeholder="Your mobile number"
                    className="w-full px-4 py-3 bg-background border border-border rounded-md text-foreground placeholder:text-foreground/40 focus:outline-none focus:ring-2 focus:ring-accent/50 transition"
                  />
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label htmlFor="program" className="block text-sm font-semibold text-foreground mb-2">
                      Program
                    </label>
                    <select
                      id="program"
                      name="program"
                      value={formData.program}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-3 bg-background border border-border rounded-md text-foreground focus:outline-none focus:ring-2 focus:ring-accent/50 transition"
                    >
                      <option value="">Select Program</option>
                      <option value="mbbs">MBBS</option>
                      <option value="engineering">Engineering</option>
                      <option value="mba">MBA</option>
                      <option value="phd">PhD</option>
                    </select>
                  </div>
                  <div>
                    <label htmlFor="destination" className="block text-sm font-semibold text-foreground mb-2">
                      Destination
                    </label>
                    <select
                      id="destination"
                      name="destination"
                      value={formData.destination}
                      onChange={handleChange}
                      required
                      className="w-full px-4 py-3 bg-background border border-border rounded-md text-foreground focus:outline-none focus:ring-2 focus:ring-accent/50 transition"
                    >
                      <option value="">Select Destination</option>
                      <option value="usa">USA</option>
                      <option value="uk">United Kingdom</option>
                      <option value="germany">Germany</option>
                      <option value="australia">Australia</option>
                      <option value="nz">New Zealand</option>
                      <option value="dubai">Dubai</option>
                    </select>
                  </div>
                </div>

                <Button
                  type="submit"
                  disabled={isLoading}
                  className="w-full bg-accent hover:bg-accent/90 text-foreground font-bold py-3 rounded-md transition-colors text-base disabled:opacity-70 disabled:cursor-not-allowed"
                >
                  {isLoading ? (
                    <span className="flex items-center justify-center gap-2">
                      <svg className="animate-spin h-5 w-5" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                        <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" />
                        <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z" />
                      </svg>
                      Submitting…
                    </span>
                  ) : (
                    'Claim My Free Consultation'
                  )}
                </Button>

                {error && (
                  <p className="text-sm text-red-600 bg-red-50 border border-red-200 rounded-md px-4 py-2 text-center">
                    {error}
                  </p>
                )}

                <p className="text-xs text-foreground/50 text-center">
                  By submitting, you agree to our Terms and Privacy Policy.
                </p>
              </form>
            )}
          </div>
        </div>
      </div>
    </section>
  );
}
